@pytest.mark.asyncio
async def test_ocr_multi_page() -> None:
    """OCR request returning multiple pages of document content."""
    client = create_client(
        api_key="test-key",
        base_url=os.environ["MOCK_SERVER_URL"] + "/fixtures/ocr_multi_page",
    )
    request = OcrRequest.from_json(
        '{"document":{"type":"document_url","url":"https://example.com/multipage.pdf"},"model":"mistral/mistral-ocr-latest"}'
    )

    result = await client.ocr(request)
    assert len(result.pages) == 2  # noqa: S101
    assert result.pages[0].index == 0  # noqa: S101
    assert result.pages[1].index == 1  # noqa: S101


